const stateRaw = $('evcc: State abrufen').first()?.json ?? {};
const evccState = stateRaw?.result ?? stateRaw;
const evopt = evccState?.evopt ?? null;

const haState = $('HA: Schwellwert lesen').first()?.json ?? {};
const thresholdCt = parseFloat(haState?.state ?? 0);
const reasoningOriginal = haState?.attributes?.reasoning ?? '(keine Begründung)';

if (!evopt?.res) {
  return [{ json: {
    evopt_available: false,
    threshold_ct: thresholdCt,
    reasoning_original: reasoningOriginal
  }}];
}

const batteries = evopt.res?.batteries ?? [];
const batteryDetails = evopt.details?.batteryDetails ?? [];
const homeBatIdx = batteryDetails.findIndex(d => d.type === 'battery');
const bat0 = batteries[homeBatIdx >= 0 ? homeBatIdx : 0] ?? {};
const chargingPower = bat0?.charging_power ?? [];
const socArr = bat0?.state_of_charge ?? [];
const timestamps = evopt.details?.timestamp ?? [];
const pricesPN = evopt.req?.time_series?.PN ?? [];

const chargeSlots = chargingPower
  .map((power, i) => ({ power, ts: timestamps[i], pn: pricesPN[i] ?? 0 }))
  .filter(s => s.power > 100 && s.ts != null);

const chargeWindows = chargeSlots.map(s => {
  const d = new Date(s.ts);
  const time = d.getHours().toString().padStart(2,'0') + ':' + d.getMinutes().toString().padStart(2,'0');
  const priceCt = Math.round(s.pn * 1000000) / 10;
  return `${time} (${priceCt} ct)`;
}).join(' | ');

const maxChargePriceCt = chargeSlots.length > 0
  ? Math.round(Math.max(...chargeSlots.map(s => s.pn * 1000000)) / 10) / 10
  : null;

const savings = Math.round(-(evopt.res?.objective_value ?? 0) * 100) / 100;

const toPct = wh => Math.round(wh / 7600 * 100);
const minSoc = socArr.length > 0 ? toPct(Math.min(...socArr)) : 0;
const maxSocVal = socArr.length > 0 ? toPct(Math.max(...socArr)) : 0;
const endSoc = socArr.length > 0 ? toPct(socArr[socArr.length - 1]) : 0;

const isSolarOnly = chargeSlots.length > 0 && maxChargePriceCt !== null && maxChargePriceCt <= 0.1;

const prompt = `Gesetzter Schwellwert: ${thresholdCt} ct/kWh\nBatterie: 7,6 kWh, Einspeisevergütung 6,7 ct/kWh\n\nevcc Optimizer-Plan:\n  Ladefenster: ${chargeWindows || 'keine (kein Netzladen geplant)'}\n  Ladeslots (15-min): ${chargeSlots.length}\n  Höchster Ladepreis: ${maxChargePriceCt !== null ? maxChargePriceCt + ' ct/kWh' : 'n/a'}\n  Geplante Kosteneinsparung: ${savings > 0 ? savings + ' €' : 'n/a'}\n  SoC-Verlauf: min ${minSoc}%, max ${maxSocVal}%, Ende ${endSoc}%\n${isSolarOnly ? '\nHINWEIS: Alle Ladeslots zeigen 0 ct – das bedeutet Solar-Laden (kein Netzimport). Der batterygridchargelimit-Schwellwert betrifft NUR Netzladen und soll in diesem Fall NICHT geändert werden. Setze status: \"ok\".\n' : ''}\nValidiere ob der Plan konsistent mit dem Schwellwert ist:\n- Ladeslots vorhanden und Preise > 0: Weicht der höchste Ladepreis stark vom Schwellwert ab (>3 ct)?\n  Wenn ja: neuen Schwellwert empfehlen (= höchster_ladepreis + 1 ct Puffer)\n- Keine Ladeslots oder Solar-Only (0 ct): status ok, Schwellwert unverändet lassen.\n\nAntworte NUR mit validem JSON:\n{\"status\": \"ok\" oder \"adjusted\", \"new_threshold_ct\": <nur wenn adjusted und Preis > 0>, \"deviation_ct\": <Differenz in ct>, \"explanation\": \"<Erklärung DE>\"}`;

return [{ json: {
  evopt_available: true,
  threshold_ct: thresholdCt,
  reasoning_original: reasoningOriginal,
  charge_windows: chargeWindows || 'keine',
  n_slots: chargeSlots.length,
  max_charge_price_ct: maxChargePriceCt,
  savings_eur: Math.max(0, savings),
  soc_min: minSoc,
  soc_max: maxSocVal,
  soc_end: endSoc,
  prompt
}}];

const item = $input.first();
const data = item?.json ?? {};
const response = data.output ?? data.text ?? data.message ?? data.content ?? JSON.stringify(data);

let status = 'ok';
let newThresholdCt = null;
let deviationCt = 0;
let explanation = 'Keine Begründung';

try {
  const direct = JSON.parse(String(response).trim());
  if (direct.status) {
    status = direct.status ?? 'ok';
    newThresholdCt = direct.new_threshold_ct != null ? parseFloat(direct.new_threshold_ct) : null;
    deviationCt = parseFloat(direct.deviation_ct ?? 0);
    explanation = direct.explanation ?? explanation;
  }
} catch(e) {
  const allMatches = [...String(response).matchAll(/\{[^{}]*"status"[^{}]*\}/g)];
  const jsonMatch = allMatches.length > 0 ? allMatches[allMatches.length - 1][0] : null;
  if (jsonMatch) {
    try {
      const parsed = JSON.parse(jsonMatch);
      status = parsed.status ?? 'ok';
      newThresholdCt = parsed.new_threshold_ct != null ? parseFloat(parsed.new_threshold_ct) : null;
      deviationCt = parseFloat(parsed.deviation_ct ?? 0);
      explanation = parsed.explanation ?? explanation;
    } catch(e2) {}
  }
}

const prepData = $('Daten aufbereiten').first()?.json ?? {};
const originalThreshold = prepData.threshold_ct ?? 0;
const finalThresholdCt = (status === 'adjusted' && newThresholdCt !== null)
  ? Math.min(50, Math.max(0, newThresholdCt))
  : originalThreshold;

const validationStatus = status === 'adjusted'
  ? `korrigiert ${originalThreshold}→${finalThresholdCt} ct: ${explanation}`
  : `validiert: ${explanation}`;

return [{ json: {
  status,
  final_threshold_ct: finalThresholdCt,
  new_threshold_ct: newThresholdCt,
  deviation_ct: deviationCt,
  explanation,
  validation_status: validationStatus,
  reasoning_original: prepData.reasoning_original ?? '',
  charge_windows: prepData.charge_windows ?? '',
  savings_eur: prepData.savings_eur ?? 0,
  timestamp: new Date().toISOString()
}}];

const usage = $('Claude: Plan validieren').first()?.json?.tokenUsage ?? {};
const inputTokens = usage.inputTokens ?? usage.prompt_tokens ?? 500;
const outputTokens = usage.outputTokens ?? usage.completion_tokens ?? 150;
const cost_usd = (inputTokens / 1000000 * 3) + (outputTokens / 1000000 * 15);
const costRounded = Math.round(cost_usd * 100000) / 100000;
return [{ json: {
  workflow: 'validator',
  input_tokens: inputTokens,
  output_tokens: outputTokens,
  cost_usd: costRounded,
  line_protocol: 'ai_costs,workflow=validator input_tokens=' + inputTokens + 'i,output_tokens=' + outputTokens + 'i,cost_usd=' + costRounded
}}];
